mapper.select:
SELECT ai.id, ai.name, ai.introduction, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ai.address_detail, ai.latitude, ai.longitude, ai.phone, ai.is_release, IFNULL(ri.total_count,0) total_room_count, IFNULL(ri.total_count,0) - IFNULL(la.lease_room_number,0) free_room_count FROM (SELECT id, name, introduction, district_id, district_name, city_id, city_name, province_id, province_name, address_detail, latitude, longitude, phone, is_release FROM apartment_info
is_deleted=0
and province_id=#{queryVo.provinceId}
and city_id=#{queryVo.cityId}
and district_id=#{queryVo.districtId}
) ai LEFT JOIN (SELECT apartment_id, COUNT(*) total_count FROM room_info WHERE is_deleted = 0 GROUP BY apartment_id) ri ON ai.id = ri.apartment_id LEFT JOIN (SELECT apartment_id,COUNT(*) lease_room_number FROM lease_agreement WHERE STATUS IN (2,5) AND is_deleted=0 GROUP BY apartment_id) la ON ai.id = la.apartment_id

select name,
       url
from graph_info
where is_deleted = 0
  and item_type = #{itemType}
  and item_id = #{id}
